// products.ts — catalog with default items embedded as base64

export type Category = string; // open-ended for custom categories

export interface CategoryMeta {
  id: string;
  label: string;
  labelRu: string;
  icon: string;
  isCustom?: boolean;
}

export const DEFAULT_CATEGORIES: CategoryMeta[] = [
  { id: "hat", label: "Hat", labelRu: "Головной убор", icon: "🧢" },
  { id: "top", label: "Top", labelRu: "Верх", icon: "👕" },
  { id: "bottom", label: "Bottom", labelRu: "Низ", icon: "👖" },
  { id: "dress", label: "Dress", labelRu: "Платье", icon: "👗" },
  { id: "shoes", label: "Shoes", labelRu: "Обувь", icon: "👟" },
  { id: "glasses", label: "Glasses", labelRu: "Очки", icon: "🕶️" },
  { id: "suit", label: "Suit", labelRu: "Костюм", icon: "🥋" },
];

export const CATEGORIES_STORAGE_KEY = "ainek_categories";

export function loadCategories(): CategoryMeta[] {
  try {
    const custom = JSON.parse(localStorage.getItem(CATEGORIES_STORAGE_KEY) || "[]");
    return [...DEFAULT_CATEGORIES, ...custom];
  } catch { return DEFAULT_CATEGORIES; }
}

// Keep CATEGORIES export for backward compat
export const CATEGORIES = DEFAULT_CATEGORIES;

export interface Product {
  id: string;
  sku: string;
  name: string;
  brand: string;
  price: number;
  currency: string;
  imageUrl: string;
  category: string;
  isDefault?: boolean;
}

